/**
 * Calculate license status from session.
 */
export function getLicenseStatus(session: LicenseSession): {
  daysRemaining: number;
  isExpired: boolean;
  isInGrace: boolean;
  isHardLocked: boolean;
  status: 'valid' | 'warning' | 'critical' | 'grace' | 'locked';
} {
  if (session.isAdmin) {
    return { daysRemaining: 9999, isExpired: false, isInGrace: false, isHardLocked: false, status: 'valid' };
  }
  const now = new Date();
  const diff = session.expiresAt.getTime() - now.getTime();
  const daysRemaining = Math.ceil(diff / (1000 * 60 * 60 * 24));
  const isExpired = daysRemaining <= 0;
  return {
    daysRemaining,
    isExpired,
    isInGrace: false,
    isHardLocked: isExpired,
    status: isExpired ? 'locked' : daysRemaining <= 7 ? 'critical' : daysRemaining <= 30 ? 'warning' : 'valid',
  };
}

